// Validate and extract dispatch payload
const payload = $json.body || $json;

if (!payload.task_id || !payload.task_run_id) {
  throw new Error('Missing required fields: task_id, task_run_id');
}

// Map agent_role to execution strategy
// PATCH: max_tokens capped at 2048 to prevent n8n cloud execution timeout
// Context payloads with large Task Contracts (3000-4500 tokens) + high max_tokens caused
// n8n cloud to timeout at ~300-600s before returning. Root cause: 2026-03-29 ERT-P1 incident.
const AGENT_PROFILES = {
  orchestrator:         { model: 'claude-opus-4-6',   max_tokens: 2048, temperature: 0.2 },
  architect:            { model: 'claude-opus-4-6',   max_tokens: 2048, temperature: 0.1 },
  product_analyst:      { model: 'claude-sonnet-4-6', max_tokens: 2048, temperature: 0.3 },
  backend_engineer:     { model: 'claude-sonnet-4-6', max_tokens: 2048, temperature: 0.1 },
  frontend_engineer:    { model: 'claude-sonnet-4-6', max_tokens: 2048, temperature: 0.2 },
  automation_engineer:  { model: 'claude-sonnet-4-6', max_tokens: 2048, temperature: 0.1 },
  integration_engineer: { model: 'claude-sonnet-4-6', max_tokens: 2048, temperature: 0.1 },
  qa_security_auditor:  { model: 'claude-opus-4-6',   max_tokens: 2048, temperature: 0.0 },
  documentation_engineer: { model: 'claude-haiku-4-5-20251001', max_tokens: 2048, temperature: 0.3 },
  cost_analyst:         { model: 'claude-haiku-4-5-20251001', max_tokens: 2048, temperature: 0.1 },
  recommendation_analyst: { model: 'claude-sonnet-4-6', max_tokens: 2048, temperature: 0.2 },
  release_manager:      { model: 'claude-opus-4-6',   max_tokens: 2048, temperature: 0.0 },
};

const profile = AGENT_PROFILES[payload.agent_role] || AGENT_PROFILES['orchestrator'];

// PATCH: Truncate context_payload to prevent timeout
// Full context_payload (9-field Task Contracts) can be 3000-4500 tokens.
// We extract only the critical fields needed for the Claude prompt.
function truncateContextPayload(cp) {
  if (!cp || typeof cp !== 'object') return '';
  const tc = cp.task_contract || cp;
  const objective = (tc.objective || cp.objective || '').slice(0, 300);
  const impl = Array.isArray(tc.implementation_plan)
    ? tc.implementation_plan.slice(0, 4).map(s => String(s).slice(0, 100)).join('\n- ')
    : (tc.implementation_plan || '').slice(0, 400);
  const expected = (tc.expected_output || cp.expected_output || '').slice(0, 200);
  const acceptance = Array.isArray(tc.acceptance_criteria)
    ? tc.acceptance_criteria.slice(0, 3).join('; ').slice(0, 200)
    : '';
  return [
    objective ? `Objective: ${objective}` : '',
    impl ? `Implementation:\n- ${impl}` : '',
    expected ? `Expected: ${expected}` : '',
    acceptance ? `Acceptance: ${acceptance}` : '',
  ].filter(Boolean).join('\n\n').slice(0, 900);
}

const truncatedContext = truncateContextPayload(payload.context_payload);


// P0 CODE GEN: flag code-type tasks so downstream nodes change prompts + call generate
const needsCodeGen = ['code', 'schema', 'test'].includes(payload.task_type || '');

const systemPrompt = needsCodeGen
  ? `You are a ${payload.agent_role} in the Build OS system. Write the implementation files exactly as described. Output ONLY fenced code blocks, each with a filename comment as the very first line. No JSON wrappers, no extra explanation.`
  : `You are a ${payload.agent_role} agent in the Build OS system. Your task is to execute the work described and return a structured JSON output matching the expected schema for task_type: ${payload.task_type}. Be precise and complete.`;

const codeInstructions = needsCodeGen
  ? `IMPORTANT: Return your implementation as fenced code blocks ONLY.\nEach block MUST have a filename comment as its first line, e.g.:\n\`\`\`typescript\n// src/lib/wizard-state.ts\n// implementation here\n\`\`\`\nSupported comment styles: // (TS/JS), # (Python/Bash), -- (SQL).`
  : `Return your output as JSON matching the schema for task_type: ${payload.task_type || 'document'}`;
return {
  ...payload,
  agent_profile: profile,
  context_payload_truncated: truncatedContext,
  started_at: new Date().toISOString(),
  needsCodeGen,
  systemPrompt,
  codeInstructions,
};

// Parse AI response and extract output + cost metrics
const aiResponse = $json;

// P0: Preserve raw Claude text for code extraction
const rawAgentText = $json.content?.[0]?.text || '';


let parsedOutput = null;
let outputType = $('Validate + Route').first().json.task_type || 'document';
let success = true;
let errorMsg = null;

try {
  const content = aiResponse.content?.[0]?.text || '';
  // Try to extract JSON from response
  const jsonMatch = content.match(/```json\n([\s\S]*?)\n```/) || 
                    content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsedOutput = JSON.parse(jsonMatch[1] || jsonMatch[0]);
  } else {
    // Treat as document output
    parsedOutput = { content, format: 'markdown' };
    outputType = 'document';
  }
} catch (e) {
  success = false;
  errorMsg = `Failed to parse AI output: ${e.message}`;
}

// Extract cost from usage metrics
const usage = aiResponse.usage || {};
const inputTokens = usage.input_tokens || 0;
const outputTokens = usage.output_tokens || 0;
const totalTokens = inputTokens + outputTokens;

// Approximate cost (Claude Sonnet 4 pricing)
const costUsd = (inputTokens * 0.000003) + (outputTokens * 0.000015);

const dispatchPayload = $('Validate + Route').first().json;

return {
  task_id: dispatchPayload.task_id,
  task_run_id: dispatchPayload.task_run_id,
  agent_role: dispatchPayload.agent_role,
  output_type: outputType,
  output: parsedOutput,
  success,
  error_message: errorMsg,
  tokens_used: totalTokens,
  model_id: aiResponse.model || dispatchPayload.agent_profile.model,
  cost_usd: Math.round(costUsd * 100000) / 100000,
  idempotency_key: dispatchPayload.idempotency_key || `agent_output:${dispatchPayload.task_run_id}`,
  rawAgentText,
};

// Create blocker on callback failure
const dispatchPayload = $('Validate + Route').first().json;
return {
  task_id: dispatchPayload.task_id,
  description: `Agent output callback failed after execution. Manual intervention required.`,
  severity: 'critical',
  task_run_id: dispatchPayload.task_run_id,
};

// Assemble the /api/agent/generate payload
const dispatchData = $('Validate + Route').first().json;
const parseData = $('Parse AI Response').first().json;
const callbackData = $('POST \u2192 /api/agent/output').first().json;

// agent_output_id from the /api/agent/output response body
const agentOutputId = callbackData?.data?.agent_output_id || null;

if (!agentOutputId) {
  throw new Error('No agent_output_id returned from /api/agent/output — cannot call generate');
}

// Use rawAgentText (the actual Claude response text, not the parsed JSON wrapper)
const rawOutput = parseData.rawAgentText || '';

return {
  project_id: dispatchData.project_id,
  task_id: dispatchData.task_id,
  agent_output_id: agentOutputId,
  agent_role: dispatchData.agent_role,
  raw_output: rawOutput,
  callback_url: dispatchData.callback_url,
};
